// Parse the incoming Unigroup request and select the right URL pair for
// the target environment. Expected message shape:
//   {
//     operation: 'graphql_query' | 'graphql_mutation' | 'upload_document',
//     query:     '...'            // for graphql_*
//     variables: { ... }          // for graphql_*
//     document:  {                // for upload_document
//       order_id:   'ORD12345',
//       filename:   'bol.pdf',
//       content_base64: '...',
//       content_type: 'application/pdf'
//     },
//     correlation_id: '...',
//     _retry_count: 0
//   }
const kafkaMessage = $input.item.json;
const msg = typeof kafkaMessage.value === 'string' ? JSON.parse(kafkaMessage.value) : kafkaMessage.value;

if (!msg || !msg.operation) {
  throw new Error('invalid unigroup-out message: missing operation');
}
const allowed = new Set(['graphql_query', 'graphql_mutation', 'upload_document']);
if (!allowed.has(msg.operation)) {
  throw new Error(`unsupported operation: ${msg.operation}`);
}

const env = ($env.UNIGROUP_ENV || 'staging').toLowerCase();
if (env !== 'staging' && env !== 'production') {
  throw new Error(`UNIGROUP_ENV must be 'staging' or 'production', got '${env}'`);
}
const suffix = env === 'production' ? 'PROD' : 'STAGING';

const tokenUrl   = $env[`UNIGROUP_TOKEN_URL_${suffix}`];
const graphqlUrl = $env[`UNIGROUP_GRAPHQL_URL_${suffix}`];
const docsUrl    = $env[`UNIGROUP_DOCS_URL_${suffix}`];
const clientId     = $env.UNIGROUP_CLIENT_ID;
const clientSecret = $env.UNIGROUP_CLIENT_SECRET;
const scope        = $env.UNIGROUP_OAUTH_SCOPE || '';

if (!clientId || !clientSecret || clientId === 'CHANGE_ME') {
  throw new Error('UNIGROUP_CLIENT_ID / UNIGROUP_CLIENT_SECRET not configured');
}

return {
  json: {
    operation:     msg.operation,
    query:         msg.query,
    variables:     msg.variables || {},
    document:      msg.document || null,
    correlation_id: msg.correlation_id || null,
    retry_count:   msg._retry_count || 0,
    max_retries:   5,
    env,
    urls:          { token: tokenUrl, graphql: graphqlUrl, docs: docsUrl },
    credentials:   { client_id: clientId, client_secret: clientSecret, scope },
    original:      msg
  }
};

// Merge token with the validated context. The token response is the current
// item; the previous step's payload is on $('Validate + Resolve Env').item.
const tokenResp = $input.item.json;
const ctx = $('Validate + Resolve Env').item.json;

if (!tokenResp.access_token) {
  throw new Error(`token endpoint did not return access_token: ${JSON.stringify(tokenResp).slice(0,200)}`);
}

return {
  json: {
    ...ctx,
    access_token: tokenResp.access_token,
    token_type:   tokenResp.token_type || 'Bearer',
    expires_in:   tokenResp.expires_in || null
  }
};

// Normalize success output. GraphQL responses include {data, errors}; a
// 200 with a non-empty errors array is still a failure at the API level.
const resp = $input.item.json;
const ctx  = $('Extract Token').item.json;
const isGraphql = ctx.operation !== 'upload_document';

if (isGraphql && Array.isArray(resp.errors) && resp.errors.length > 0) {
  throw new Error(`GraphQL errors: ${JSON.stringify(resp.errors).slice(0,500)}`);
}

return {
  json: {
    success: true,
    workflow: 'unigroup-outbound',
    operation: ctx.operation,
    correlation_id: ctx.correlation_id,
    response: resp,
    env: ctx.env,
    timestamp: new Date().toISOString()
  }
};

// Decide retry vs DLQ. 401 = token issue (retry once after forcing a fresh
// token fetch; since we fetch per-run this happens automatically on requeue).
// 429 / 5xx = transient. 4xx else = permanent, straight to DLQ.
const error = $input.item.json;
const ctx = $('Validate + Resolve Env').item ? $('Validate + Resolve Env').item.json : {};
const retryCount = ctx.retry_count || 0;
const maxRetries = ctx.max_retries || 5;
const status = error.status || error.statusCode || (error.response && error.response.status) || 0;
const isTransient = status === 401 || status === 429 || (status >= 500 && status < 600);
const shouldRetry = isTransient && retryCount < maxRetries;

return {
  json: {
    workflow: 'unigroup-outbound',
    operation: ctx.operation,
    correlation_id: ctx.correlation_id,
    error_message: error.message || (error.response && error.response.statusText) || 'unknown error',
    status,
    retry_count: retryCount,
    max_retries: maxRetries,
    should_retry: shouldRetry,
    retry_delay_ms: Math.min(60000, 1000 * Math.pow(2, retryCount)) + Math.floor(Math.random() * 500),
    requeue_payload: { ...(ctx.original || {}), _retry_count: retryCount + 1 },
    timestamp: new Date().toISOString()
  }
};
